+// Archive moves a message to the archive file and removes it from inbox.
+func (m *Mailbox) Archive(id string) error {
+	// Get the message first
+	msg, err := m.Get(id)
+	if err != nil {
+		return err
+	}
+
+	// Append to archive file
+	if err := m.appendToArchive(msg); err != nil {
+		return err
+	}
+
+	// Delete from inbox
+	return m.Delete(id)
+}
